package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Constructor;

class CSVFormatTest {

    @Test
    void testGetIgnoreSurroundingSpaces_DefaultIsFalse() throws Exception {
        Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(
                char.class, Character.class, QuoteMode.class, Character.class, Character.class,
                boolean.class, boolean.class, String.class, String.class, Object[].class, String[].class,
                boolean.class, boolean.class, boolean.class, boolean.class, boolean.class, boolean.class);
        constructor.setAccessible(true);
        CSVFormat format = constructor.newInstance(',', '"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false, false);
        assertFalse(format.getIgnoreSurroundingSpaces());
    }

    @Test
    void testGetIgnoreSurroundingSpaces_WithIgnoreSurroundingSpacesTrue() throws Exception {
        Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(
                char.class, Character.class, QuoteMode.class, Character.class, Character.class,
                boolean.class, boolean.class, String.class, String.class, Object[].class, String[].class,
                boolean.class, boolean.class, boolean.class, boolean.class, boolean.class, boolean.class);
        constructor.setAccessible(true);
        CSVFormat format = constructor.newInstance(',', '"', null, null, null, true, true, "\r\n",
                null, null, null, false, false, false, false, false, false);
        assertTrue(format.getIgnoreSurroundingSpaces());
    }

    @Test
    void testGetIgnoreSurroundingSpaces_StaticConstants() {
        assertFalse(CSVFormat.DEFAULT.getIgnoreSurroundingSpaces());
        assertTrue(CSVFormat.TDF.getIgnoreSurroundingSpaces());
    }
}
